CREATE OR REPLACE FUNCTION sync_filter_to_module_filter()
RETURNS TRIGGER AS $$
BEGIN
    IF pg_trigger_depth() > 1 THEN
        IF (TG_OP = 'DELETE') THEN RETURN OLD; END IF;
        RETURN NEW;
    END IF;

    IF (TG_OP = 'INSERT') THEN
        INSERT INTO module_filter (
            filter_id, name, description, sql_statement,
            status_id, date_created, date_updated, owner_id, update_id
        )
        VALUES (
            NEW.filter_id, NEW.name, NEW.description, NEW.sql_statement,
            NEW.status_id, NEW.date_created, NEW.date_updated, NEW.owner_id, NEW.update_id
        )
        ON CONFLICT (filter_id) DO UPDATE SET
            name = EXCLUDED.name,
            description = EXCLUDED.description,
            sql_statement = EXCLUDED.sql_statement,
            status_id = EXCLUDED.status_id,
            date_created = EXCLUDED.date_created,
            date_updated = EXCLUDED.date_updated,
            owner_id = EXCLUDED.owner_id,
            update_id = EXCLUDED.update_id;
        RETURN NEW;
    ELSIF (TG_OP = 'UPDATE') THEN
        UPDATE module_filter SET
            name = NEW.name,
            description = NEW.description,
            sql_statement = NEW.sql_statement,
            status_id = NEW.status_id,
            date_created = NEW.date_created,
            date_updated = NEW.date_updated,
            owner_id = NEW.owner_id,
            update_id = NEW.update_id
        WHERE filter_id = OLD.filter_id;
        RETURN NEW;
    ELSIF (TG_OP = 'DELETE') THEN
        DELETE FROM module_filter WHERE filter_id = OLD.filter_id;
        RETURN OLD;
    END IF;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_sync_filter_to_module ON filter;
CREATE TRIGGER trg_sync_filter_to_module
AFTER INSERT OR UPDATE OR DELETE ON filter
FOR EACH ROW EXECUTE FUNCTION sync_filter_to_module_filter();

